          'image' => 
          array (
            'file' => 'freccia2_l4356q9t.jpg',
            'alt' => '',
          ),
        ),
        2 => 
        array (
          'type' => 'figure',
          'image' => 
          array (
            'file' => 'botton_03.jpg',
            'alt' => '',
            'link' => 'https://shop.moruzzi.it/en/coins/coins-of-the-kingdom-of-italy/victor-emmanuel-iii-1900-1943.html',
