            'alt' => '',
          ),
        ),
        2 => 
        array (
          'type' => 'text',
          'paragraphs' => 
          array (
            0 => 'This great Spanish gold coin weighing 27,07 grams, coined for the first time in 1611, during Philip\'s III era, was particularly appreciated in Europe and South America, where circulated the exemplar coined in many Spanish mints. It was also the reference currency in countries not placed under Spanish control, such as North America and even the Far East.<br>',
